import React, { useState, useEffect, useCallback } from 'react';
import { View, Text, Button, StyleSheet, ActivityIndicator, Alert } from 'react-native';
import { authorize, refresh, revoke } from 'react-native-app-auth';

// OAuth 2.0 Configuration
// IMPORTANT: Replace all 'YOUR_...' placeholders with your actual OAuth provider details.
// For `react-native-app-auth` setup, ensure you link the library and configure
// your redirect URL scheme in your project settings (e.g., info.plist for iOS, AndroidManifest.xml for Android).
const config = {
  issuer: 'YOUR_OAUTH_ISSUER_URL', // e.g., 'https://accounts.google.com' or 'https://your-auth-server.com'
  clientId: 'mobile_app_client_123',
  clientSecret: 'secret_abc123xyz456', // Declared as requested. For public clients (like mobile apps), `client_secret` is generally NOT used in the token exchange for security reasons. `react-native-app-auth` handles PKCE correctly for public clients.
  redirectUrl: 'YOUR_APP_SCHEME://oauth', // e.g., 'com.yourapp.bundleid://oauth' or 'exp://192.168.1.2:19000/--/oauth' for Expo Go
  scopes: ['openid', 'profile', 'email', 'offline_access'], // Adjust requested scopes as needed
  serviceConfiguration: { // If your issuer URL does not support OIDC discovery, provide explicit endpoints:
    authorizationEndpoint: 'YOUR_AUTHORIZATION_ENDPOINT', // e.g., 'https://your-auth-server.com/oauth/authorize'
    tokenEndpoint: 'YOUR_TOKEN_ENDPOINT', // e.g., 'https://your-auth-server.com/oauth/token'
    revocationEndpoint: 'YOUR_REVOCATION_ENDPOINT', // e.g., 'https://your-auth-server.com/oauth/revoke'
  },
};

const App = () => {
  const [authState, setAuthState] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleAuthorize = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const authResult = await authorize(config);
      setAuthState(authResult);
    } catch (e) {
      setError(`Authorization failed: ${e.message}`);
      console.error('Authorization failed:', e);
    } finally {
      setLoading(false);
    }
  }, []);

  const handleRefresh = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      if (!authState || !authState.refreshToken) {
        Alert.alert('Error', 'No refresh token available. Please log in first.');
        setLoading(false);
        return;
      }
      const refreshedState = await refresh(config, {
        refreshToken: authState.refreshToken,
      });
      setAuthState(refreshedState);
    } catch (e) {
      setError(`Refresh failed: ${e.message}`);
      console.error('Refresh failed:', e);
    } finally {
      setLoading(false);
    }
  }, [authState]);

  const handleRevoke = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      if (!authState || !authState.accessToken) {
        Alert.alert('Error', 'No access token available.');
        setLoading(false);
        return;
      }
      await revoke(config, {
        token: authState.accessToken,
        sendClientId: true, // Some providers require client_id for revocation
      });
      setAuthState(null);
      Alert.alert('Success', 'Tokens revoked.');
    } catch (e) {
      setError(`Revocation failed: ${e.message}`);
      console.error('Revocation failed:', e);
    } finally {
      setLoading(false);
    }
  }, [authState]);

  const renderAuthStatus = () => {
    if (loading) {
      return (
        <View style={styles.statusContainer}>
          <ActivityIndicator size="large" color="#0000ff" />
          <Text style={styles.statusText}>Loading...</Text>
        </View>
      );
    }

    if (error) {
      return (
        <View style={styles.statusContainer}>
          <Text style={styles.errorText}>Error: {error}</Text>
        </View>
      );
    }

    if (authState) {
      return (
        <View style={styles.statusContainer}>
          <Text style={styles.statusTitle}>Logged In!</Text>
          <Text style={styles.tokenText}>Access Token: {authState.accessToken ? authState.accessToken.substring(0, 30) + '...' : 'N/A'}</Text>
          <Text style={styles.tokenText}>Refresh Token: {authState.refreshToken ? authState.refreshToken.substring(0, 30) + '...' : 'N/A'}</Text>
          <Text style={styles.tokenText}>Expires In: {authState.accessTokenExpirationDate ? new Date(authState.accessTokenExpirationDate).toLocaleTimeString() : 'N/A'}</Text>
          <Text style={styles.tokenText}>ID Token: {authState.idToken ? authState.idToken.substring(0, 30) + '...' : 'N/A'}</Text>
          <View style={styles.buttonGroup}>
            <Button title="Refresh Token" onPress={handleRefresh} disabled={!authState.refreshToken || loading} />
            <Button title="Revoke Tokens" onPress={handleRevoke} disabled={!authState.accessToken || loading} color="#dc3545" />
          </View>
        </View>
      );
    }

    return (
      <View style={styles.statusContainer}>
        <Text style={styles.statusText}>Not logged in.</Text>
      </View>
    );
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>OAuth 2.0 React Native App</Text>
      <Button
        title="Login with OAuth"
        onPress={handleAuthorize}
        disabled={loading}
      />
      {renderAuthStatus()}
    </View>
  );
};

